CREATE TABLE IF NOT EXISTS audience_sequence_schedule_intents (
  id TEXT PRIMARY KEY,
  sequence_id TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'dry_run_recorded',
  schedule_kind TEXT NOT NULL DEFAULT 'owner_confirmed_dry_run',
  expected_workspace_revision_id TEXT NOT NULL,
  expected_sequence_status TEXT NOT NULL,
  ready_enrollment_count INTEGER NOT NULL DEFAULT 0,
  held_enrollment_count INTEGER NOT NULL DEFAULT 0,
  active_suppression_count INTEGER NOT NULL DEFAULT 0,
  requested_start_at TEXT,
  idempotency_key TEXT NOT NULL,
  actor_user_id TEXT NOT NULL,
  actor_email TEXT NOT NULL,
  metadata_json TEXT,
  created_at INTEGER NOT NULL DEFAULT (unixepoch()),
  updated_at INTEGER NOT NULL DEFAULT (unixepoch())
);

CREATE UNIQUE INDEX IF NOT EXISTS audience_sequence_schedule_intents_idempotency_unique
  ON audience_sequence_schedule_intents(idempotency_key);

CREATE INDEX IF NOT EXISTS audience_sequence_schedule_intents_sequence_status_idx
  ON audience_sequence_schedule_intents(sequence_id, status);

CREATE INDEX IF NOT EXISTS audience_sequence_schedule_intents_status_created_idx
  ON audience_sequence_schedule_intents(status, created_at);

